// src/App.jsx
import React from "react";
import { BrowserRouter } from "react-router-dom";
import Navbar from "./components/Navbar/Navbar";
import Hero from "./components/Hero/Hero";
import Section from "./components/Section/Section";

function App() {
  return (
    <BrowserRouter>
      <Navbar /* searchData will be wired in later milestones */ />
      <Hero />
      {/* M-2: Top Albums section using Card and Section */}
      <Section />
      {/* Later: add a second Section for New Albums if required */}
    </BrowserRouter>
  );
}

export default App;
